'use client';

import { useState, ReactNode, useEffect } from 'react';
import {
  PopupModelContext,
  ModalState,
  ModalType,
} from '@/context/PopupModelContext';

import PopupModel from '@/components/PopupModel';

export const PopupModelProvider = ({ children }: { children: ReactNode }) => {
  const [modal, setModal] = useState<ModalState>({
    type: null,
    data: null,
  });

  // ✅ OPEN MODAL
  const openModel = (type: ModalType, data?: any) => {
    setModal({ type, data });
  };

  // ✅ CLOSE MODAL
  const closeModel = () => {
    setModal({ type: null, data: null });
  };

  // ✅ LOCK SCROLL (IMPORTANT)
  useEffect(() => {
    if (modal.type) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
    }

    return () => {
      document.body.style.overflow = '';
    };
  }, [modal.type]);

  return (
    <PopupModelContext.Provider value={{ openModel, closeModel, modal }}>
      {children}

      {/* 🔥 CENTRALIZED MODAL RENDER */}
      {modal.type === 'PROJECT' && (
        <PopupModel isOpen={true} onClose={closeModel} project={modal.data} />
      )}
    </PopupModelContext.Provider>
  );
};
